#include<bits/stdc++.h>
using namespace std;
long long n,l,id;
bool vis[101][101];
long long dp[101][101],a[101];
long long dfs(long long x,long long cnt)
{
    if(cnt>l)
    {
        return 0;
    }
    if(x==0)
    {
        return 1;
    }
    if(vis[x][cnt])
    {
        return dp[x][cnt];
    }
    vis[x][cnt]=true;
    dp[x][cnt]=0;
    dp[x][cnt]+=dfs(x-1,cnt);
    dp[x][cnt]+=dfs(x-1,cnt+1);
    return dp[x][cnt];
}
void dfs1(long long x,long long cnt,long long k)
{
    if(x==0)
    {
        for(long long i=n;i>=1;i--)
        {
            printf("%lld",a[i]);
        }
        exit(0);
    }
    if(k<=dfs(x-1,cnt))
    {
        a[x]=0;
        dfs1(x-1,cnt,k);
    }
    else
    {
        a[x]=1;
        dfs1(x-1,cnt+1,k-dfs(x-1,cnt));
    }
}
int main()
{
    scanf("%lld%lld%lld",&n,&l,&id);
    dfs1(n,0,id);
    return 0;
}
